def calc_area(length, width=None):
    if width is None:
        return length * length
    return length * width

print(calc_area(10))     # Square
print(calc_area(10, 5))  # Rectangle

def sum_all(*args):
    total = 0
    for n in args:
        total += n
    return total

print(sum_all(1, 2, 3, 4, 5))

def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

print(fibonacci(7))  # Output: 13
